.box {
  background: #a5b4fc;   /* يظهر خلف المحتوى والحشوة */
  padding: 20px;          /* حشوة داخلية */
  border: 4px solid #4338ca;
  margin: 24px;           /* هامش خارجي شفاف */
}

.container {
  width: 60%;
  margin: 0 auto;
  background: #bbf7d0;
  padding: 12px;
  text-align: center;
}

.a, .b { width: 200px; padding: 20px; border: 4px solid #333; }
.a { box-sizing: content-box; } /* العرض الفعلي 248px */
.b { box-sizing: border-box; }  /* العرض الفعلي 200px */
